class Solution:
    def maximumImportance(self, n, roads):
        deg = [0] * n
        for a, b in roads:
            deg[a] += 1
            deg[b] += 1
        order = sorted(range(n), key=lambda c: deg[c])
        value = [0] * n
        for rank, city in enumerate(order):
            value[city] = rank + 1
        total = 0
        for a, b in roads:
            total += value[a] + value[b]
        return total

