class Solution:
    def maximumImportance(self, n, roads):
        deg = [0] * n
        for a, b in roads:
            deg[a] += 1
            deg[b] += 1
        deg.sort()
        total = 0
        for i in range(n):
            total += deg[i] * (i + 1)
        return total

