var maximumImportance = function(n, roads) {
    const deg = new Array(n).fill(0);
    for (const [a, b] of roads) {
        deg[a]++;
        deg[b]++;
    }
    deg.sort((x, y) => x - y);
    let total = 0;
    for (let i = 0; i < n; i++) {
        total += deg[i] * (i + 1);
    }
    return total;
};
